from typing import List

class Solution:
    def minCostToEqualizeArray(self, nums: List[int], cost1: int, cost2: int) -> int:
        MOD = 10**9 + 7
        n = len(nums)
        nums.sort()
        total_cost = 0
        for i in range(1, n):
            diff = nums[i] - nums[i - 1]
            if cost2 < cost1 * 2:
                total_cost += diff * cost2
            else:
                total_cost += diff * cost1
        return total_cost % MOD
